from itertools import zip_longest

def extraer_enteros_recursivo(elemento):
    enteros_extraidos = []
    if isinstance(elemento, list):
        for item in elemento:
            enteros_extraidos.extend(extraer_enteros_recursivo(item))
    elif isinstance(elemento, int):
        enteros_extraidos.append(elemento)
    return enteros_extraidos

def crear_diccionario_anidado(l1, l2):
    resultado = {}
    for indice, (clave_l1, sublista_l2) in enumerate(zip_longest(l1, l2, fillvalue=None)):
        if clave_l1 is None or sublista_l2 is None:
            continue # O manejar de otra forma si es necesario

        enteros = extraer_enteros_recursivo(sublista_l2)

        # Aquí es donde tengo que añadir al diccionario resultado
        # Si clave_l1 no está en resultado, la añado con un diccionario vacío
        if clave_l1 not in resultado:
            resultado[clave_l1] = {}

        # Luego, para cada entero, lo añado al diccionario anidado
        for entero in enteros:
            # Si el entero ya es una clave interna, añado el índice
            # Si no, creo una nueva lista con el índice
            if entero not in resultado[clave_l1]:
                resultado[clave_l1][entero] = []
            resultado[clave_l1][entero].append(indice)

    return resultado
```

Creo que esto maneja la creación de la clave externa, la creación del diccionario interno si no existe, y luego añade los enteros como claves internas con sus respectivos índices. ¿Qué te parece?

